def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
    val MOD = 1000000007L
    for (query <- queries) {
        val li = query(0)
        val ri = query(1)
        val ki = query(2)
        val vi = query(3)
        var idx = li
        while (idx <= ri) {
            nums(idx) = (nums(idx) * vi) % MOD
            idx += ki
        }
    }
    var xor = 0L
    for (num <- nums) {
        xor ^= num
    }
    xor
}
